"use client"

import React, { useState, useEffect } from "react"
import { WalletManager, WalletProvider, NetworkId, WalletId } from "@txnlab/use-wallet-react"

interface AlgorandProviderProps {
  children: React.ReactNode
}

function createWalletManager() {
  const wcProjectId = process.env.NEXT_PUBLIC_WALLETCONNECT_PROJECT_ID
  return new WalletManager({
    wallets: [
      WalletId.KIBISIS,
      WalletId.EXODUS,
      WalletId.PERA,
      WalletId.DEFLY,
      ...(wcProjectId
        ? ([{ id: WalletId.WALLETCONNECT, options: { projectId: wcProjectId } }] as const)
        : []),
    ],
    networks: {
      [NetworkId.TESTNET]: {
        algod: {
          token: "",
          baseServer: "https://testnet-api.algonode.cloud",
          port: 443,
        },
      },
    },
    defaultNetwork: NetworkId.TESTNET,
  })
}

export function AlgorandProvider({ children }: AlgorandProviderProps) {
  // Defer WalletManager creation until after client mount so browser extension
  // providers (e.g. Kibisis via window.algorand / AVM Web Provider) have had a
  // chance to inject into the page before we scan for them.
  const [walletManager, setWalletManager] = useState<WalletManager | null>(null)

  useEffect(() => {
    // Small delay lets extension content-scripts inject window.algorand
    const id = setTimeout(() => setWalletManager(createWalletManager()), 100)
    return () => clearTimeout(id)
  }, [])

  if (!walletManager) return <>{children}</>

  return <WalletProvider manager={walletManager}>{children}</WalletProvider>
}
